// settings (VS Code)
{
  "claude-code.model": "claude-sonnet-4-6",
  "claude-code.autoApprove": false,
  "claude-code.theme": "dark"
}

import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });

const message = await client.messages.create({
  model: "claude-sonnet-4-6",
  max_tokens: 1024,
  messages: [{ role: "user", content: "Explique recursão" }],
});

console.log(message.content[0].text);

const stream = await client.messages.create({
  model: "claude-sonnet-4-6",
  max_tokens: 1024,
  stream: true,
  messages: [{ role: "user", content: "Explique O(n log n)" }],
});

for await (const chunk of stream) {
  if (chunk.type === "content_block_delta") {
    process.stdout.write(chunk.delta.text);
  }
}

const response = await client.messages.create({
  model: "claude-sonnet-4-6",
  tools: [{
    name: "get_weather",
    description: "Get current weather for a city",
    input_schema: {
      type: "object",
      properties: {
        city: { type: "string", description: "City name" }
      },
      required: ["city"]
    }
  }],
  messages: [{ role: "user", content: "Qual o tempo em São Paulo?" }],
});

import { Agent } from "@anthropic-ai/agent-sdk";

const agent = new Agent({
  model: "claude-sonnet-4-6",
  instructions: "Você é um assistente de desenvolvimento. Ajude com código TypeScript.",
  tools: [
    {
      name: "read_file",
      description: "Read a file from disk",
      execute: async ({ path }) => fs.readFileSync(path, "utf-8"),
    }
  ],
});

const result = await agent.run("Analise meu package.json e sugira atualizações");
